proof_block:
// The proof fn's ensures has the shape `H ==> det_equal`, where H is
// the conjunction of the two original ensures (one for r1, one for
// r2). The previous attempt asserted the conjuncts of H directly at
// the top level, but H is the *antecedent* of an implication, not a
// hypothesis of the proof body — so those asserts failed.
//
// To make the ensures conjuncts available as hypotheses, wrap the
// whole proof block in `if H { ... }`. Inside the `if`, every
// conjunct of H is a fact, so the mirrored asserts verify trivially
// and Verus records them as conditional facts (`H ==> assertion`).
// During the postcondition check, Verus assumes H (the antecedent of
// the implication), the conditional facts become unconditional, and
// z3 sees both copies of each spec-fn call
// (`well_typed_events`, `receive_packet_next`,
// `raw_io_consistent_with_spec_io`, `no_invalid_sends`,
// `HostState::invariants`) at the top level, with matching shape —
// closing the trigger gap that produced the SMT `unknown`.
//
// `==>` is rewritten as `!a || b` inside the `if` condition to avoid
// any precedence/parsing ambiguity for the nested implications coming
// from the original ensures.
if (post1_self_.invariants(&post1_netc.my_end_point()))
    && (post1_self_@.constants == pre_self_@.constants)
    && (r1.0 == post1_netc.ok())
    && (!(r1.0 || (r1.1)@.sends.len() > 0)
        || (post1_netc.history() == old_netc_history + (r1.1)@.ios))
    && ((r1.1)@.ios == (r1.1)@.event_seq())
    && ((r1.1)@.well_typed_events())
    && (!r1.0
        || (receive_packet_next(pre_self_@, post1_self_@, (r1.2)@)
            && raw_io_consistent_with_spec_io((r1.1)@.ios, (r1.2)@)
            && no_invalid_sends((r1.2)@)))
    && (post2_self_.invariants(&post2_netc.my_end_point()))
    && (post2_self_@.constants == pre_self_@.constants)
    && (r2.0 == post2_netc.ok())
    && (!(r2.0 || (r2.1)@.sends.len() > 0)
        || (post2_netc.history() == old_netc_history + (r2.1)@.ios))
    && ((r2.1)@.ios == (r2.1)@.event_seq())
    && ((r2.1)@.well_typed_events())
    && (!r2.0
        || (receive_packet_next(pre_self_@, post2_self_@, (r2.2)@)
            && raw_io_consistent_with_spec_io((r2.1)@.ios, (r2.2)@)
            && no_invalid_sends((r2.2)@)))
{
    // Each assertion below is a direct conjunct of the if-condition,
    // hence verified by Verus from the hypothesis side. They mirror
    // the original ensures for both r1 and r2 in identical shape,
    // forcing z3 to instantiate the inner foralls of the spec fns
    // symmetrically for the two runs.
    assert(post1_self_.invariants(&post1_netc.my_end_point()));
    assert(post2_self_.invariants(&post2_netc.my_end_point()));
    assert(post1_self_@.constants == pre_self_@.constants);
    assert(post2_self_@.constants == pre_self_@.constants);
    assert(r1.0 == post1_netc.ok());
    assert(r2.0 == post2_netc.ok());
    assert((r1.0 || (r1.1)@.sends.len() > 0)
        ==> post1_netc.history() == old_netc_history + (r1.1)@.ios);
    assert((r2.0 || (r2.1)@.sends.len() > 0)
        ==> post2_netc.history() == old_netc_history + (r2.1)@.ios);
    assert((r1.1)@.ios == (r1.1)@.event_seq());
    assert((r2.1)@.ios == (r2.1)@.event_seq());
    assert((r1.1)@.well_typed_events());
    assert((r2.1)@.well_typed_events());
    assert(r1.0 ==> receive_packet_next(pre_self_@, post1_self_@, (r1.2)@));
    assert(r2.0 ==> receive_packet_next(pre_self_@, post2_self_@, (r2.2)@));
    assert(r1.0 ==> raw_io_consistent_with_spec_io((r1.1)@.ios, (r1.2)@));
    assert(r2.0 ==> raw_io_consistent_with_spec_io((r2.1)@.ios, (r2.2)@));
    assert(r1.0 ==> no_invalid_sends((r1.2)@));
    assert(r2.0 ==> no_invalid_sends((r2.2)@));
}
